/**
 * Generated by `createservice notification.SyncRemoteClientService --type mutations`
 */
const chunk = require('lodash/chunk')
const get = require('lodash/get')
const isEqual = require('lodash/isEqual')
const pickBy = require('lodash/pickBy')

const { GQLError, GQLErrorCode: { BAD_USER_INPUT } } = require('@open-condo/keystone/errors')
const { GQLCustomSchema, getById, getByCondition, getSchemaCtx, find } = require('@open-condo/keystone/schema')
const { wrapWithGQLError } = require('@open-condo/keystone/utils/errors/wrapWithGQLError')

const { UUID_REGEXP } = require('@condo/domains/common/constants/regexps')
const access = require('@condo/domains/notification/access/SyncRemoteClientService')
const { PUSH_TRANSPORT_TYPES, DEVICE_PLATFORM_TYPES, PUSH_TYPES } = require('@condo/domains/notification/constants/constants')
const { DEVICE_KEY_VALIDATION_ERROR, INVALID_DEVICE_KEY } = require('@condo/domains/notification/constants/errors')
const { RemoteClient, RemoteClientPushToken } = require('@condo/domains/notification/utils/serverSchema')
const { getPushTokensValidationError, deduplicatePushTokens, PUSH_TOKENS_VALIDATION_ERRORS } = require('@condo/domains/notification/utils/serverSchema/syncRemoteClient/pushTokensInput')

const ERRORS = {
    ...PUSH_TOKENS_VALIDATION_ERRORS,
    DEVICE_KEY_VALIDATION_ERROR: {
        code: BAD_USER_INPUT,
        type: DEVICE_KEY_VALIDATION_ERROR,
        message: '"deviceKey" validation error',
    },
    INVALID_DEVICE_KEY: {
        code: BAD_USER_INPUT,
        type: INVALID_DEVICE_KEY,
        message: '"deviceKey" should be a valid UUID',
    },
}

const SENSITIVE_FIELDS = [
    /^push/,
    /^meta$/,
    /^owner$/,
]

function _cleanRemoteClient (rawClient) {
    return Object.fromEntries(
        Object.entries(rawClient).map(([key, value]) => ([
            key,
            SENSITIVE_FIELDS.some(field => field.test(key)) ? null : value,
        ]))
    )
}

async function loadRemoteClientPushTokens (remoteClient, pushTokensInput) {
    const resultById = {}

    const remoteClientTokens = await find('RemoteClientPushToken', {
        remoteClient: { id: remoteClient.id },
    })
    for (const token of remoteClientTokens) {
        resultById[token.id] = token
    }

    for (const pushTokensChunk of chunk(pushTokensInput, 10)) {
        const currentPushTokens = await find('RemoteClientPushToken', {
            AND: [{
                remoteClient: { id_not: remoteClient.id },
                OR: pushTokensChunk.map(pushToken => ({
                    AND: [{
                        token: pushToken.token,
                        provider: pushToken.provider,
                    }],
                })),
            }],
        })
        for (const token of currentPushTokens) {
            resultById[token.id] = token
        }
    }

    return Object.values(resultById)
}

function getPushTokenKey (provider, token) {
    return `${provider}:${token}`
}

function buildExistingMaps (existingPushTokens, remoteClientId) {
    const existingByKey = {}
    const existingByProviderForRemoteClient = {}

    for (const existingPushToken of existingPushTokens) {
        const key = getPushTokenKey(existingPushToken.provider, existingPushToken.token)
        existingByKey[key] = existingPushToken

        if (
            existingPushToken.remoteClient !== remoteClientId
            || existingPushToken.deletedAt
        ) continue

        if (!existingByProviderForRemoteClient[existingPushToken.provider]) {
            existingByProviderForRemoteClient[existingPushToken.provider] = []
        }
        existingByProviderForRemoteClient[existingPushToken.provider].push(existingPushToken)
    }

    return { existingByKey, existingByProviderForRemoteClient }
}

function mergeUpdateJobsById (jobs) {
    const jobIdsOrder = new Set(jobs.map(job => job.id))
    const merged = {}
    for (const job of jobs) {
        if (!merged[job.id]) {
            merged[job.id] = job
            continue
        }

        merged[job.id] = {
            id: job.id,
            data: {
                ...merged[job.id].data,
                ...job.data,
            },
        }
    }
    const result = []
    for (const jobId of jobIdsOrder.values()) {
        result.push(merged[jobId])
    }
    return result
}

function buildDesiredStateFromInput (pushTokensInput, remoteClientId) {
    const desiredByKey = {}
    const desiredByProvider = {}

    for (const pushToken of pushTokensInput) {
        const isPush = !!pushToken.isPush
        const isVoIP = !!pushToken.isVoIP
        if (!isPush && !isVoIP) continue // NOTE: shouldn't happen as pushTokensInput are validated before call

        const desired = {
            remoteClientId,
            token: pushToken.token,
            provider: pushToken.provider,
            isPush,
            isVoIP,
        }
        const key = getPushTokenKey(desired.provider, desired.token)
        desiredByKey[key] = desired

        if (!desiredByProvider[desired.provider]) desiredByProvider[desired.provider] = []
        desiredByProvider[desired.provider].push(desired)
    }

    return { desiredByKey, desiredByProvider }
}

function buildCreateOrUpdateJobs ({ desiredByKey, existingByKey, dv, sender }) {
    const jobs = { create: [], update: [] }

    for (const desired of desiredByKey.values()) {
        const key = getPushTokenKey(desired.provider, desired.token)
        const existing = existingByKey.get(key)

        if (!existing) {
            jobs.create.push({
                data: {
                    dv,
                    sender,
                    remoteClient: { connect: { id: desired.remoteClientId } },
                    token: desired.token,
                    provider: desired.provider,
                    isPush: desired.isPush,
                    isVoIP: desired.isVoIP,
                },
            })
            continue
        }

        const needsRemoteClientUpdate = existing.remoteClient !== desired.remoteClientId
        const needsIsPushUpdate = existing.isPush !== desired.isPush
        const needsIsVoIPUpdate = existing.isVoIP !== desired.isVoIP
        const needsRestore = !!existing.deletedAt

        if (needsRemoteClientUpdate || needsIsPushUpdate || needsIsVoIPUpdate || needsRestore) {
            const data = { dv, sender }
            if (needsRemoteClientUpdate) data.remoteClient = { connect: { id: desired.remoteClientId } }
            if (needsIsPushUpdate) data.isPush = desired.isPush
            if (needsIsVoIPUpdate) data.isVoIP = desired.isVoIP
            if (needsRestore) data.deletedAt = null
            jobs.update.push({ id: existing.id, data })
        }
    }

    return jobs
}

function getDesiredWinnerByProvider (desiredByProvider) {
    return Object.fromEntries(
        Object.entries(desiredByProvider).map(([provider, desiredTokens]) => {
            return [provider, {
                pushToken: desiredTokens.find(d => d.isPush)?.token || null,
                voIPToken: desiredTokens.find(d => d.isVoIP)?.token || null,
            }]
        })
    )
}

function getOldTokenResolutionOp (existingToken, { shouldDisablePush, shouldDisableVoIP }) {
    const resultingIsPush = shouldDisablePush ? false : !!existingToken.isPush
    const resultingIsVoIP = shouldDisableVoIP ? false : !!existingToken.isVoIP

    if (!resultingIsPush && !resultingIsVoIP) return { action: 'delete' }

    const data = {}
    if (shouldDisablePush) data.isPush = false
    if (shouldDisableVoIP) data.isVoIP = false

    return { action: 'update', data }
}

function buildConflictResolutionJobs ({ desiredByProvider, existingByProviderForRemoteClient, dv, sender }) {
    const winnersByProvider = getDesiredWinnerByProvider(desiredByProvider)
    const demotionsById = {}

    for (const [provider, winners] of Object.entries(winnersByProvider)) {
        const existingOfProvider = existingByProviderForRemoteClient[provider] || []

        const tokensDemotions = existingOfProvider.map(existingToken => {
            const shouldDisablePush = winners.pushToken && existingToken.isPush && existingToken.token !== winners.pushToken
            const shouldDisableVoIP = winners.voIPToken && existingToken.isVoIP && existingToken.token !== winners.voIPToken
            if (!shouldDisablePush && !shouldDisableVoIP) return null
            return { existingToken, shouldDisableVoIP, shouldDisablePush }
        }).filter(Boolean)

        const operationsToDemoteTokens = tokensDemotions.map(({ existingToken, shouldDisablePush, shouldDisableVoIP }) => ({
            existingToken, 
            op: getOldTokenResolutionOp(existingToken, { shouldDisablePush, shouldDisableVoIP }),
        }))

        const demotionsByIdForProvider = operationsToDemoteTokens.reduce((demotionsByIdForProvider, { existingToken, op }) => {
            const prevOp = demotionsByIdForProvider[existingToken.id]
            if (!prevOp) {
                demotionsById[existingToken.id] = op
            } else if (prevOp.action !== 'delete') {
                if (op.action === 'delete') {
                    demotionsById[existingToken.id] = op
                } else {
                    demotionsById[existingToken.id] = {
                        action: 'update',
                        data: {
                            ...prevOp.data,
                            ...op.data,
                        },
                    }
                }
            }
        }, {})

        Object.assign(demotionsById, demotionsByIdForProvider)


        // for (const existingToken of existingOfProvider) {
        //     const shouldDisablePush = winners.pushToken && existingToken.isPush && existingToken.token !== winners.pushToken
        //     const shouldDisableVoIP = winners.voIPToken && existingToken.isVoIP && existingToken.token !== winners.voIPToken
        //     if (!shouldDisablePush && !shouldDisableVoIP) continue
        //
        //     const opToResolvePushTokenInCurrentStep = getOldTokenResolutionOp(existingToken, { shouldDisablePush, shouldDisableVoIP })
        //
        //     const prevOp = demotionsById[existingToken.id]
        //     if (!prevOp) {
        //         demotionsById[existingToken.id] = opToResolvePushTokenInCurrentStep
        //     } else if (prevOp.action !== 'delete') {
        //         if (opToResolvePushTokenInCurrentStep.action === 'delete') {
        //             demotionsById[existingToken.id] = opToResolvePushTokenInCurrentStep
        //         } else {
        //             demotionsById[existingToken.id] = {
        //                 action: 'update',
        //                 data: {
        //                     ...prevOp.data,
        //                     ...opToResolvePushTokenInCurrentStep.data,
        //                 },
        //             }
        //         }
        //     }
        // }
    }
    
    const jobs = { update: [], delete: [] }
    for (const [id, op] of Object.entries(demotionsById)) {
        if (op.action === 'delete') {
            jobs.delete.push({
                id,
                data: {
                    dv,
                    sender,
                    deletedAt: new Date().toISOString(),
                },
            })
        } else {
            jobs.update.push({
                id,
                data: {
                    dv,
                    sender,
                    ...op.data,
                },
            })
        }
    }

    return jobs
}

async function syncPushTokens (context, { remoteClient, pushTokensInput, dv, sender }) {
    const existingPushTokens = await loadRemoteClientPushTokens(remoteClient, pushTokensInput)

    const { existingByKey, existingByProviderForRemoteClient } = buildExistingMaps(existingPushTokens, remoteClient.id)
    const { desiredByKey, desiredByProvider } = buildDesiredStateFromInput(pushTokensInput, remoteClient.id)

    const jobs = buildCreateOrUpdateJobs({ desiredByKey, existingByKey, dv, sender })
    const conflictsJobs = buildConflictResolutionJobs({ desiredByProvider, existingByProviderForRemoteClient, dv, sender })

    const mergedUpdateJobs = mergeUpdateJobsById([
        ...conflictsJobs.delete,
        ...jobs.delete,
        ...conflictsJobs.update,
        ...jobs.update,
    ])

    await RemoteClientPushToken.updateMany(context, mergedUpdateJobs)
    await RemoteClientPushToken.createMany(context, jobs.create)

    return jobs
}

async function syncRemoteClient (context, { userId, dv, sender, deviceId, appId, devicePlatform, pushType, pushTypeVoIP, meta }) {
    const attrs = pickBy({
        dv, sender, deviceId, appId,
        pushToken: null, pushTokenVoIP: null,
        pushTransport: null, pushTransportVoIP: null,
        devicePlatform, pushType, meta,
        pushTypeVoIP,
        owner: userId ? { disconnectAll: true, connect: { id: userId } } : null,
    }, value => value !== undefined)

    const existing = await getByCondition('RemoteClient', { deviceId, appId })

    if (!existing) {
        return await RemoteClient.create(context, attrs)
    }
    const diff = {}
    for (const [key, value] of Object.entries(attrs)) {
        if (key === 'sender') continue

        if (key === 'owner') {
            const existingOwnerId =  existing?.owner
            const newOwnerId = value?.connect?.id ?? null

            if (existingOwnerId !== newOwnerId) {
                diff.owner = value
            }

            continue
        }
        if (!isEqual(existing[key], value)) {
            diff[key] = value
        }
    }

    if (Object.keys(diff).length > 0) {
        return await RemoteClient.update(context, existing.id, attrs)
    }
    return existing
}


const SyncRemoteClientService = new GQLCustomSchema('SyncRemoteClientService', {
    types: [
        {
            access: true,
            type: `enum PushTransportType { ${PUSH_TRANSPORT_TYPES.join(' ')} }`,
        },
        {
            access: true,
            type: `enum DevicePlatformType { ${DEVICE_PLATFORM_TYPES.join(' ')} }`,
        },
        {
            access: true,
            type: `enum PushType { ${PUSH_TYPES.join(' ')} }`,
        },
        {
            access: true,
            type: `input PushToken {
                    token: String!,
                    transport: PushTransportType!,
                    """
                    Specifies if token can be used to receive default push messages
                    """
                    isPush: Boolean!
                     """
                    Specifies if token can be used to receive VoIP push messages
                    """
                    isVoIP: Boolean!,
                }
            `,
        },
        {
            access: true,
            type: `input SyncRemoteClientInput { 
                dv: Int!, 
                sender: SenderFieldInput!,
                
                appId: String!,
                deviceId: String!,
                """
                Second private factor of ownership to remote client, since deviceId is treated as public info. If not provided or changed, existing tokens will be deleted
                """
                deviceKey: ID,
                devicePlatform: DevicePlatformType,
                
                """
                Preferred way to receive default push messages on this device
                """
                pushType: PushType,
                """
                Preferred way to receive VoIP push messages on this device
                """
                pushTypeVoIP: PushType,
                
                pushToken: String @deprecated(reason: "Use pushTokens instead"),
                pushTransport: PushTransportType @deprecated(reason: "Use pushTokens instead"),
                
                pushTokenVoIP: String @deprecated(reason: "Use pushTokens instead"),
                pushTransportVoIP: PushTransportType @deprecated(reason: "Use pushTokens instead"),
                
                """
                List of tokens received from messaging providers / sdks
                """
                pushTokens: [PushToken!],
                
                meta: JSON,
            }`,
        },
    ],

    mutations: [
        {
            access: access.canSyncRemoteClient,
            schema: 'syncRemoteClient(data: SyncRemoteClientInput!): RemoteClient',
            doc: {
                errors: ERRORS,
            },
            resolver: async (parent, args, context) => {
                const {
                    data: {
                        dv, sender, deviceId, appId, devicePlatform, meta,
                        pushType,
                        pushTypeVoIP,
                        deviceKey,
                    },
                } = args
                let {
                    data: { pushToken, pushTransport, pushTokenVoIP, pushTransportVoIP, pushTokens: pushTokensRaw },
                } = args
                pushTokensRaw ??= []

                const pushTokensInput = pushTokensRaw.map(pushTokenRaw => ({
                    token: pushTokenRaw.token,
                    provider: pushTokenRaw.transport,
                    isPush: pushTokenRaw.isPush,
                    isVoIP: pushTokenRaw.isVoIP,
                }))

                if (pushToken && pushTransport) {
                    pushTokensInput.push({
                        token: pushToken,
                        provider: pushTransport,
                        isVoIP: false,
                        isPush: true,
                    })
                }
                if (pushTokenVoIP && pushTransportVoIP) {
                    pushTokensInput.push({
                        token: pushTokenVoIP,
                        provider: pushTransportVoIP,
                        isVoIP: true,
                        isPush: false,
                    })
                }

                const pushTokensValidationError = getPushTokensValidationError(pushTokensInput)
                if (pushTokensValidationError) {
                    throw new GQLError(pushTokensValidationError, context)
                }
                const pushTokens = deduplicatePushTokens(pushTokensInput)

                // TODO(YEgorLu): after DOMA-13021 this check should use RemoteClient.deviceToken field instead of User.password
                if (typeof deviceKey === 'string') {
                    const isValidUuid = UUID_REGEXP.test(deviceKey)
                    if (!isValidUuid) {
                        throw new GQLError(ERRORS.INVALID_DEVICE_KEY, context)
                    }
                    // NOTE(YEgorLu): this will be changed from 'User' to 'RemoteClient'
                    const { keystone } = getSchemaCtx('User')
                    try {
                        // NOTE(YEgorLu): this will be changed from 'User' to 'RemoteClient'
                        keystone.lists['User'].fieldsByPath.password.validateNewPassword(deviceKey)
                    } catch (err) {
                        throw wrapWithGQLError(err, context, ERRORS.DYNAMIC_DEVICE_KEY_VALIDATION_ERROR)
                    }
                }

                const userId = get(context, 'authedItem.id', null)
                const remoteClient = await syncRemoteClient(context, { userId, dv, sender, deviceId, appId, devicePlatform, pushType, pushTypeVoIP, meta })
                await syncPushTokens(context, { remoteClient, pushTokensInput: pushTokens, dv, sender })

                const client = await getById('RemoteClient', remoteClient.id)
                return _cleanRemoteClient(client)
            },
        },
    ],
})

module.exports = {
    SyncRemoteClientService,
    ERRORS,
}
